"use client";

import React from "react";
import Link from "next/link";
import { motion } from "framer-motion";
import { Quote } from "@/lib/types";
import { useQuotes } from "@/context/QuotesContext";
import { useToast } from "@/context/ToastContext";
import { LikeButton } from "./LikeButton";
import { ShareButton } from "./ShareButton";
import { TagBadge } from "./TagBadge";
import { Quote as QuoteIcon, ExternalLink } from "lucide-react";

interface QuoteCardProps {
  quote: Quote;
  showFullMeta?: boolean;
  animationDelay?: number;
}

export function QuoteCard({ quote, showFullMeta = true, animationDelay = 0 }: QuoteCardProps) {
  const { addLike, addDislike, getReaction } = useQuotes();
  const { addToast } = useToast();
  const reaction = getReaction(quote._id);

  const handleLike = () => {
    addLike(quote);
    if (reaction?.type !== "liked") {
      addToast("Added to favorites!", "success");
    }
  };

  const handleDislike = () => {
    addDislike(quote);
  };

  return (
    <motion.article
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -20 }}
      transition={{ duration: 0.4, delay: animationDelay }}
      className="group relative bg-white dark:bg-gray-800 rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 p-6 md:p-8 border border-gray-100 dark:border-gray-700"
    >
      {/* Quote Icon */}
      <div className="absolute -top-4 left-6 bg-gradient-to-br from-primary-500 to-accent-500 rounded-full p-3 shadow-lg">
        <QuoteIcon className="w-5 h-5 text-white" />
      </div>

      {/* Quote Content */}
      <blockquote className="mt-4 mb-6">
        <p className="text-lg md:text-xl lg:text-2xl font-serif text-gray-800 dark:text-gray-100 leading-relaxed">
          &ldquo;{quote.content}&rdquo;
        </p>
      </blockquote>

      {/* Author */}
      <div className="flex items-center justify-between flex-wrap gap-4">
        <Link
          href={`/author/${quote.authorSlug}`}
          className="text-primary-600 dark:text-primary-400 font-medium hover:underline transition-colors"
        >
          — {quote.author}
        </Link>

        {/* Actions */}
        <div className="flex items-center gap-2">
          <ShareButton quote={quote} />
          <LikeButton
            isLiked={reaction?.type === "liked"}
            isDisliked={reaction?.type === "disliked"}
            onLike={handleLike}
            onDislike={handleDislike}
          />
        </div>
      </div>

      {/* Metadata */}
      {showFullMeta && (
        <div className="mt-4 pt-4 border-t border-gray-100 dark:border-gray-700">
          <div className="flex flex-wrap items-center gap-2">
            {quote.tags.map((tag) => (
              <TagBadge key={tag} tag={tag} />
            ))}
            <span className="text-xs text-gray-400 dark:text-gray-500 ml-auto">
              {quote.length} characters
            </span>
          </div>
        </div>
      )}

      {/* Hover Effect Gradient */}
      <div className="absolute inset-0 rounded-2xl bg-gradient-to-br from-primary-500/5 to-accent-500/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none" />
    </motion.article>
  );
}
