"use client";

import React from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";

interface TagBadgeProps {
  tag: string;
  clickable?: boolean;
}

export function TagBadge({ tag, clickable = true }: TagBadgeProps) {
  const searchParams = useSearchParams();
  
  const content = (
    <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-primary-100 dark:bg-primary-900/30 text-primary-700 dark:text-primary-300 ${clickable ? "hover:bg-primary-200 dark:hover:bg-primary-800/50 cursor-pointer transition-colors" : ""}`}>
      {tag}
    </span>
  );

  if (!clickable) return content;

  const params = new URLSearchParams(searchParams.toString());
  params.set("tags", tag);
  params.delete("page");

  return (
    <Link href={`/search?${params.toString()}`}>
      {content}
    </Link>
  );
}
